function tollImportCell(row,names){for(var i=0;i<names.length;i++){var v=row[String(names[i]||'').toLowerCase().replace(/[^a-z0-9]+/g,'')];if(v!=null&&String(v).trim())return String(v).trim()}return''}function tollImportAmount(v){var n=Number(String(v||'').replace(/[^0-9.-]/g,''));return isNaN(n)?0:n}function tollDelimitedCells(line,delim){var out=[],value='',quoted=false;for(var i=0;i<line.length;i++){var ch=line.charAt(i);if(ch==='"'){if(quoted&&line.charAt(i+1)==='"'){value+='"';i++}else quoted=!quoted}else if(ch===delim&&!quoted){out.push(value.trim());value=''}else value+=ch}out.push(value.trim());return out}function parseTollImportRows(raw){raw=String(raw||'').trim();if(!raw)return[];if(raw.charAt(0)==='['){try{return JSON.parse(raw).map(function(x){return x||{}}).slice(0,2000)}catch(e){}}var lines=raw.split(/\r?\n/).filter(function(l){return String(l||'').trim()}).slice(0,2001),delim=lines[0]&&lines[0].indexOf('\t')>=0?'\t':',';if(!lines.length)return[];var first=tollDelimitedCells(lines[0],delim),hasHeader=first.some(function(c){return /plate|tag|customer|amount|date|notice|ticket|agency|source|vehicle|vin|location/i.test(c)}),headers=hasHeader?first.map(function(h){return h.toLowerCase().replace(/[^a-z0-9]+/g,'')}):['plate','date','amount','reference','provider','customer','notes'];return lines.slice(hasHeader?1:0).map(function(line){var c=tollDelimitedCells(line,delim),row={};headers.forEach(function(h,i){row[h||('column'+i)]=c[i]||''});return row}).filter(function(r){return Object.keys(r).some(function(k){return String(r[k]||'').trim()})})}
function matchTollImportRow(row){var plate=normName(tollImportCell(row,['plate','tag','licenseplate','currenttag','currentplate','ref','reference'])).replace(/[^a-z0-9]/g,''),customer=tollImportCell(row,['customer','name','driver','renter']),vin=normName(tollImportCell(row,['vin'])),vehicleText=normName(tollImportCell(row,['vehicle','car','unit'])),car=(db.vehicles||[]).find(function(v){var ids=[v.plate,v.stock,v.tempTag].map(function(x){return normName(x).replace(/[^a-z0-9]/g,'')});return plate&&ids.indexOf(plate)>=0})||(db.vehicles||[]).find(function(v){return vin&&normName(v.vin)===vin})||(db.vehicles||[]).find(function(v){return vehicleText&&normName(vehicleName(v)).indexOf(vehicleText)>=0});if(!customer&&car&&car.currentCustomer)customer=car.currentCustomer;if(!car&&customer)car=findVehicleByCustomer(customer)||findVehicle(existingCustomerProfile(customer).vehicleId)||null;var profile=customer?existingCustomerProfile(customer):{};return{customer:customer,car:car||{},profile:profile||{}}}
