function tollTagMappingVehicleOptions(){var list=(db.vehicles||[]).filter(function(v){return String(v.status||'').toLowerCase()!=='removed'}).slice().sort(function(a,b){return vehicleName(a).localeCompare(vehicleName(b))});return '<option value="">Unknown - send rows to Missing file</option><option value="__personal__">Personal / company vehicle - never charge a customer</option>'+list.map(function(v){var label=[vehicleName(v),'VIN '+(v.vin||'Not saved'),'Tag '+(v.plate||v.stock||'Not saved'),v.currentCustomer?'Customer '+v.currentCustomer:'In lot'].join(' | ');return '<option value="'+esc(v.id)+'">'+esc(label)+'</option>'}).join('')}
function tollTagMappingPanel(result){var groups=result&&result.tagGroups||[];if(!groups.length)return'';return '<section class="toll-tag-mapping-panel"><div class="section-head"><div><h3>Resolve repeated tags before import</h3><p>Map a fleet transponder once, mark personal/company cars so they can never become customer charges, or leave it unknown for the Missing file.</p></div>'+badge(groups.length+' tags','warn')+'</div><div class="toll-tag-mapping-grid">'+groups.map(function(g,i){var id='tollTagMap'+i,providers=(g.providers||[]).join(', ')||'E-ZPass';return '<div class="toll-tag-mapping-card"><div class="item-row"><strong>'+esc(g.tag)+'</strong><b class="money">'+money(g.total||0)+'</b></div><div class="muted">'+esc(g.count)+' transaction'+(g.count===1?'':'s')+' | '+esc(g.firstTransactionDate||'')+' to '+esc(g.lastTransactionDate||'')+' | '+esc(providers)+'</div><label><span>Search fleet</span><input type="search" data-toll-map-search="'+esc(id)+'" placeholder="Year, make, model, VIN, tag, or customer"></label><label><span>Classification / vehicle</span><select id="'+esc(id)+'" data-toll-tag-map data-tag="'+esc(g.tag)+'" data-start="'+esc(g.firstTransactionDate||'')+'" data-end="'+esc(g.lastTransactionDate||'')+'">'+tollTagMappingVehicleOptions()+'</select></label><div class="toll-tag-map-dates"><label><span>Effective from</span><input type="date" data-toll-map-start="'+esc(id)+'" value="'+esc(g.firstTransactionDate||'')+'"></label><label><span>Through</span><input type="date" data-toll-map-end="'+esc(id)+'" value="'+esc(g.lastTransactionDate||'')+'"></label></div></div>'}).join('')+'</div><div class="actions"><button class="btn gold" data-action="save-toll-tag-mappings">Save selected maps and re-preview</button></div></section>'}
