function stripeCutoverPlanIdentity(row,requireConfirmation){row=row||{};var car=findVehicle(row.vehicleId)||findVehicleByCustomer(row.customer)||{},migration=row.stripeMigration||{},subscription=String(requireConfirmation&&(migration.scheduledCloverSubscriptionId||row.stripeCutoverCloverSubscriptionId)||row.cloverSubscriptionId||row.subscriptionId||'').trim(),vehicle=row.vehicle||(car.id?vehicleName(car):'No vehicle linked'),vin=row.vin||car.vin||'VIN missing',tag=row.licensePlate||row.plate||car.plate||car.stock||'Tag missing',plan=[money(row.amount||0),row.frequency||'Weekly'].join(' | '),confirm=requireConfirmation?'<div class="field span2"><label>Type the exact Clover subscription ID</label><input id="providerCloverSubscriptionConfirmation" autocomplete="off" spellcheck="false" placeholder="Type '+esc(subscription||'the exact subscription ID')+'"></div>':'';return '<section class="notice mini stripe-cutover-plan-identity"><strong>Exact recurring plan</strong><div>'+esc(plan)+'</div><div class="muted">'+esc(vehicle+' | '+vin+' | '+tag)+'</div><div class="field span2"><label>Clover subscription ID</label><div class="input-like">'+esc(subscription||'Missing - cutover blocked')+'</div></div>'+confirm+'</section>'}
