if(a==='check-stripe-readiness'){var stripeCheck=await post('/api/integrations/stripe/readiness',{});if(!stripeCheck.ok){notify(stripeCheck.error||'Stripe account readiness check failed');return}await refreshData(true);openModal('Stripe account activation',stripeAccountReadinessReview(stripeCheck.stripeAccount||{}));notify(stripeCheck.stripeAccount&&stripeCheck.stripeAccount.live?'Stripe live account proof is current':'Stripe account checked. Review the remaining activation step.');return}
