function returnPrepCommandBoard(){var items=returnPrepCommandItems(),bad=items.filter(function(i){return i.tone==='bad'}).length,warn=items.filter(function(i){return i.tone==='warn'}).length;return '<section class="card section return-prep-command-board" data-limit="10"><div class="section-head"><div><h2>Return & prep command</h2><p>Returned customers, stale assignments, ready/prep cars, mileage handoff, and vehicle identity before the next autopay customer.</p></div><div class="star-command-stats"><span class="bad">'+bad+' fix</span><span class="warn">'+warn+' review</span><span class="blue">'+items.length+' total</span></div></div>'+localSearch('Search return/prep by customer, VIN, tag, tracker, mileage, status, or prep issue')+'<div class="role-command-grid return-prep-grid">'+(items.length?items.map(roleCommandCard).join(''):'<div class="item">Return/prep handoff is clean right now: no stale assignments, prep blockers, or ready-car identity gaps are surfaced.</div>')+'</div><div class="notice">Use this after a customer ends or swaps cars: stop autopay, move the customer to history, clear the old car, prep it, then assign it from the ready-fleet picker.</div></section>'}
