function messageTimeValue(m){var value=m&&(m.createdAt||m.date||''),time=Date.parse(value);return Number.isFinite(time)?time:0}
function messageThreadKey(m){return clientPhoneKey(messagePhoneValue(m))||normName(messageEmailValue(m))||normName(m.customer)||m.id}
function messageThreads(){var map={};(db.messages||[]).forEach(function(m){var k=messageThreadKey(m),phone=messagePhoneValue(m),email=messageEmailValue(m);if(!map[k])map[k]={key:k,customer:m.customer||'Unknown texter',phone:phone,email:email,last:m,items:[]};map[k].items.push(m);if(messageTimeValue(m)>messageTimeValue(map[k].last))map[k].last=m;if(m.customer&&!/^Unknown|Customer$/i.test(m.customer))map[k].customer=m.customer;if(phone)map[k].phone=phone;if(email)map[k].email=email});return Object.keys(map).map(function(k){var x=map[k];x.items=x.items.sort(function(a,b){return messageTimeValue(a)-messageTimeValue(b)});return x}).sort(function(a,b){return messageTimeValue(b.last)-messageTimeValue(a.last)})}
function smsDeliveryNeedsReview(message){return isOwner()&&/confirmation pending/i.test(String(message&&message.status||''))&&/^woa-sms-[a-f0-9]{64}$/.test(String(message&&message.providerIdempotencyKey||''))&&!message.deliveryReviewOutcome}
function smsDeliveryReviewButton(message){return smsDeliveryNeedsReview(message)?'<button class="btn gold" data-action="review-sms-delivery" data-id="'+esc(message.id)+'">Review delivery</button>':''}
function openSmsDeliveryReview(message){var contact=formatPhone(message.phone||message.to||message.from)||'No phone saved';openModal('Review SMS delivery','<div class="notice warn"><strong>Check Telnyx before choosing.</strong><br>The carrier response was interrupted, so WheelsonAuto blocked every automatic retry. Confirm the customer, time, destination, and message in Telnyx first.</div><div class="item"><strong>'+esc(message.customer||'Unknown customer')+'</strong><div>'+esc(contact+' | '+(message.provider||'SMS provider'))+'</div><div class="muted">'+esc(message.body||message.subject||'No message text saved')+'</div></div><div class="field" style="margin-top:12px"><label>Owner review note</label><textarea id="smsDeliveryReviewNote" placeholder="What Telnyx shows, provider message ID, or why retry is safe"></textarea></div><div class="actions" style="margin-top:12px"><button class="btn primary" data-action="confirm-sms-delivered" data-id="'+esc(message.id)+'">Carrier shows delivered</button><button class="btn danger" data-action="release-sms-retry" data-id="'+esc(message.id)+'">Carrier shows no send - allow retry</button><button class="btn" data-action="close-modal">Back</button></div>')}
function messageCard(m){var inbound=String(m.direction||'').toLowerCase().indexOf('in')>=0,ai=/AI|Star/i.test(String(m.direction||m.channel||m.source||''));var label=m.status||m.direction||'Logged',contact=formatPhone(m.phone||m.from||m.to)||m.email||'';return '<div class="message-card '+(inbound?'inbound':'outbound')+(ai?' star-message':'')+'"><div class="item-row"><strong>'+esc(m.customer||'Unknown customer')+'</strong>'+badge(label,m.tone||statusTone(label))+'</div><div class="muted">'+esc([m.date,contact,m.channel||'SMS',m.provider||''].filter(Boolean).join(' - '))+'</div><div>'+esc(m.body||m.subject||m.template||'No message text saved')+'</div><div class="actions">'+smsDeliveryReviewButton(m)+'<button class="btn" data-action="open-message-log" data-id="'+esc(m.id)+'">Open</button>'+(!ai?'<button class="btn gold" data-action="star-ai-reply" data-id="'+esc(m.id)+'">Star reply</button>':'')+'<button class="btn primary" data-action="compose-message" data-id="reply-'+esc(m.id)+'">Reply</button></div></div>'}
function messageConversationCard(t){var last=t.last||{},contact=messageContact(t.customer),phone=t.phone||contact.phone||'',email=t.email||contact.email||'',ai=/AI|Star/i.test(String(last.direction||last.channel||last.source||'')),searchText=(t.items||[]).map(function(m){return[m.customer,m.phone,m.email,m.from,m.to,m.subject,m.body,m.template].filter(Boolean).join(' ')}).join(' ');return '<button class="message-thread-card message-thread-row '+(activeMessageThreadKey===t.key?'active ':'')+(ai?'star-thread':'')+'" data-action="select-message-thread" data-id="'+esc(t.key)+'"><span hidden>'+esc(searchText)+'</span><div class="message-thread-head"><div><strong>'+esc(t.customer||'Unknown texter')+'</strong><small>'+esc(formatPhone(phone)||email||'No contact saved')+'</small></div>'+badge(last.status||last.direction||'Message',last.tone||statusTone(last.status||'Message'))+'</div><div class="message-thread-body">'+esc(last.body||last.subject||'No recent message body')+'</div><div class="message-thread-foot"><span>'+esc(last.date||shortDate(last.createdAt)||'')+'</span><span>'+esc((t.items||[]).length+' msg')+'</span></div></button>'}
function shortDate(v){if(!v)return'';var d=new Date(v);if(isNaN(d.getTime()))return String(v||'');return d.toLocaleString([], {month:'short',day:'numeric',hour:'numeric',minute:'2-digit'})}
function messageThreadContext(t){var contact=messageContact(t&&t.customer),rec=findRecurringByCustomer(t&&t.customer),car=findVehicleByCustomer(t&&t.customer),phone=t&&t.phone||contact.phone||rec&&rec.phone||'',email=t&&t.email||contact.email||rec&&rec.email||'';return{phone:phone,email:email,vehicle:car?vehicleName(car):(rec&&enrichedVehicleForRecurring(rec)||''),vin:car&&car.vin||rec&&rec.vin||'',tag:car&&(car.plate||car.stock)||rec&&(rec.licensePlate||rec.plate)||'',tracker:car&&car.tracker||rec&&rec.tracker||'',amount:rec&&rec.amount||0,status:rec&&rec.status||''}}
