requestAnimationFrame(function(){
  requestAnimationFrame(function(){
    if(typeof window.scrollTo==='function')window.scrollTo(0,0);
    if(document.documentElement)document.documentElement.scrollTop=0;
    if(document.body)document.body.scrollTop=0;
    var sidebar=document.querySelector('.sidebar');
    if(sidebar){sidebar.scrollTop=0;sidebar.scrollLeft=0}
  })
});

// The focused workspaces render in a few milliseconds. Keep navigation atomic
// so a busy or backgrounded tab never gets stuck between two workspaces.
queueRender=function(){
  if(renderQueued)return;
  renderQueued=true;
  document.body.classList.add('fast-tab-switch');
  try{
    render()
  }finally{
    renderQueued=false;
    document.body.classList.remove('fast-tab-switch')
  }
};

