function render(){
  if(!window.__woaBootReady)return;
  if(view==='Apply')view=isPublic?'Apply':'Website';
  if(view==='Apply')return Apply();
  if(nav.indexOf(view)<0)view=currentUser.homeView||nav[0]||'Dashboard';
  var renderStarted=renderClock();
  __woaPerformanceRenderMemo={};
  try{
    ({'Dashboard':Dashboard,'Today':Today,'Applications':Applications,'Operations':Operations,'Fleet':Fleet,'Contracts':Contracts,'Customers':Contracts,'Payments':Payments,'Dispatch':Dispatch,'Maintenance':Maintenance,'Documents':Documents,'Tolls':Tolls,'Insurance':Insurance,'Marketing':Marketing,'Claims & Issues':ClaimsIssues,'Mechanic Portal':MechanicPortal,'Manager Portal':ManagerPortal,'Messages':Messages,'Reports':Reports,'Utilities':Utilities,'Companies':Organizations,'API Roadmap':ApiRoadmap,'Website':Website,'Settings':Settings}[view]||Dashboard)();
    scrubRoleUi()
  }finally{
    __woaPerformanceRenderMemo=null;
    var metric={view:view,tab:tab,ms:Math.round((renderClock()-renderStarted)*10)/10,at:new Date().toISOString()};
    window.__woaLastRenderMetric=metric;
    window.__woaRenderMetrics=(window.__woaRenderMetrics||[]).concat(metric).slice(-30)
  }
}

document.addEventListener('click',function(e){
  var button=e.target.closest('button[data-view]');
  if(!button||button.dataset.view===view)return;
  function resetWorkspaceScroll(){
    if(typeof window.scrollTo==='function')window.scrollTo(0,0);
    if(document.documentElement)document.documentElement.scrollTop=0;
    if(document.body)document.body.scrollTop=0;
    var main=document.querySelector('.main');
    if(main)main.scrollTop=0;
    var sidebar=document.querySelector('.sidebar');
    if(sidebar){sidebar.scrollTop=0;sidebar.scrollLeft=0}
  }
  resetWorkspaceScroll();
  requestAnimationFrame(function(){requestAnimationFrame(resetWorkspaceScroll)})
},true);

function isCurrentAutopayRow(r){
  return recurringEligibleForToday(r)
}

function customerIdentityMatch(a,b){
  a=normName(a);b=normName(b);
  if(!a||!b)return false;
  if(a===b)return true;
  var left=a.split(/\s+/).filter(Boolean),right=b.split(/\s+/).filter(Boolean);
  if(left.length<2||right.length<2)return false;
  var sameLast=left[left.length-1]===right[right.length-1],leftFirst=left[0],rightFirst=right[0];
  var closeFirst=leftFirst===rightFirst||(leftFirst.length>=4&&rightFirst.length>=4&&leftFirst.slice(0,4)===rightFirst.slice(0,4));
  return sameLast&&closeFirst
}

// Keep unrelated sidebar groups closed when the user changes workspaces.
// This prevents previously visited Reports/Admin pages from expanding Payments.
navSections=function(){
  var role=roleName();
  var groups=role==='mechanic'?
    [['Today',['Mechanic Portal']],['Service',['Maintenance']],['Fleet',['Fleet']],['Issues',['Claims & Issues']],['Account',['Settings']]]:
    role==='manager'?
      [['Home',['Manager Portal']],['Customers',['Customers']],['Operations',['Operations']],['Office',['Messages','Reports']],['Account',['Settings']]]:
      [['Home',['Dashboard']],['Money & Customers',['Payments']],['Operations',['Operations']],['Office',['Messages','Reports']],['Admin',['Website','Settings','Companies','API Roadmap']]];
  return groups.map(function(group){
    var items=group[1].filter(function(name){return nav.indexOf(name)>=0});
    if(!items.length)return'';
    if(items.length===1)return '<div class="nav-single">'+navButton(items[0])+'</div>';
    var open=items.indexOf(view)>=0;
    return '<details class="nav-group" data-nav-group="'+esc(group[0])+'" '+(open?'open':'')+'><summary>'+esc(group[0])+'<small>'+items.length+'</small></summary><div>'+items.map(navButton).join('')+'</div></details>'
  }).join('')
};

// Use direct current-record lookup for a customer file instead of sorting the
// entire payment roster every time File is clicked.
findRecurringByCustomer=function(name){
  var key=normName(name);
  if(!key)return null;
  var rows=(cloverMembers()||[]).concat(db.recurringPayments||[]),exact=rows.find(function(r){return normName(r.customer)===key});
  if(exact)return exact;
  var close=rows.filter(function(r){return customerIdentityMatch(r.customer,name)});
  return close.length===1?close[0]:null
};

findVehicleByCustomer=function(name){
  var key=normName(name),rows=(db.vehicles||[]).filter(function(v){return normName(v.currentCustomer)});
  if(!key)return null;
  var exact=rows.filter(function(v){return normName(v.currentCustomer)===key});
  if(exact.length===1)return exact[0];
  if(exact.length>1)return null;
  var close=rows.filter(function(v){return customerIdentityMatch(v.currentCustomer,name)});
  return close.length===1?close[0]:null
};

customerFileVehicleOptions=function(customer,selected){
  var key=normName(customer),list=(db.vehicles||[]).filter(function(v){return String(v.status||'').toLowerCase()!=='removed'});
  function rank(v){
    if(v.id===selected)return 0;
    if(key&&customerIdentityMatch(v.currentCustomer,customer))return 1;
    if(isInventoryVehicle(v))return 2;
    if(v.currentCustomer)return 3;
    return 4
  }
  list.sort(function(a,b){return rank(a)-rank(b)||vehicleName(a).localeCompare(vehicleName(b))});
  return '<option value="">No vehicle selected</option>'+list.map(function(v){
    var tag=v.plate||v.stock||'No tag saved',vin=v.vin||'No VIN saved',tracker=v.tracker||'No tracker',sameCustomer=key&&customerIdentityMatch(v.currentCustomer,customer);
    var ownership=sameCustomer?(v.id===selected?'CURRENT SELECTED CAR FOR '+customer:'ALSO ASSIGNED TO '+customer+' - choose the exact current car'):(v.currentCustomer?'ASSIGNED TO '+v.currentCustomer+' - selecting transfers it':'READY FLEET');
    var label=[ownership,vehicleName(v),'VIN '+vin,'Tag '+tag,'Tracker '+tracker].join(' | ');
    return '<option value="'+esc(v.id)+'" '+(v.id===selected?'selected':'')+'>'+esc(label)+'</option>'
  }).join('')
};

var __woaSingleVehicleTransferBase=transferVehicleToCustomer;
transferVehicleToCustomer=function(vehicle,oldCustomer,newCustomer,patch){
  var key=normName(newCustomer),stamp=new Date().toISOString();
  (db.vehicles||[]).forEach(function(other){
    if(!vehicle||other.id===vehicle.id||!key||normName(other.currentCustomer)!==key)return;
    releaseCustomerVehicleOnly(newCustomer,other,'Extra vehicle assignment released when the exact current car was saved.');
    other.currentCustomer='';
    other.status='Ready';
    other.manuallyEditedAt=stamp
  });
  return __woaSingleVehicleTransferBase(vehicle,oldCustomer,newCustomer,patch)
};

var __woaCurrentCustomerRecordsBase=paymentCustomerRecords;
paymentCustomerRecords=function(roster,mode){
  var rows=__woaCurrentCustomerRecordsBase(roster);
  rows=rows.map(function(record){
    var rec=record.rec||{},contract=record.contract||{},customer=record.customer||{},car=record.car||{};
    var current=rec.id?isCurrentAutopayRow(rec):!!(
      contract.id&&activeLinkStatus(contract.status)||
      customer.id&&activeLinkStatus(customer.status||customer.stage)||
      car.id&&String(car.status||'').toLowerCase()!=='removed'&&normName(car.currentCustomer)
    );
    return Object.assign({},record,{active:current,history:!current})
  });
  if(mode==='Active')rows=rows.filter(function(record){return record.active});
  if(mode==='History')rows=rows.filter(function(record){return record.history});
  return rows.sort(function(a,b){return (a.active===b.active?0:(a.active?-1:1))||String(a.name||'').localeCompare(String(b.name||''))})
};

var __woaFastCustomerFileOpenBase=openContract;
openContract=function(id){
  var previousMemo=__woaPerformanceRenderMemo;
  __woaPerformanceRenderMemo={};
  try{return __woaFastCustomerFileOpenBase(id)}finally{__woaPerformanceRenderMemo=previousMemo}
};

// A customer file already updates its linked customer, vehicle, autopay, and
// service rows before saving. Avoid a second full reconciliation and download.
var __woaStateSaveInFlight=false;
var __woaLastDataVersion=window.__SERVER_DATA_VERSION__||'';
var __woaRefreshOutsideSaveBase=refreshData;
var __woaStateRefreshInFlight=null;
var __woaRuntimeTabId='tab-'+Date.now().toString(36)+'-'+Math.random().toString(36).slice(2,10);
var __woaRuntimeLeasePrefix='woa-runtime-lease:';
var __woaStateBroadcastKey='woa-runtime-state-change';

function __woaReadRuntimeJson(key){
  try{return JSON.parse(localStorage.getItem(key)||'null')}catch(error){return null}
}

function __woaClaimRuntimeLease(name,ttl){
  var key=__woaRuntimeLeasePrefix+name,nowMs=Date.now(),current=__woaReadRuntimeJson(key)||{};
  if(current.owner&&current.owner!==__woaRuntimeTabId&&Number(current.expiresAt||0)>nowMs)return false;
  var next={owner:__woaRuntimeTabId,expiresAt:nowMs+Math.max(1000,Number(ttl||0))};
  try{
    localStorage.setItem(key,JSON.stringify(next));
    var confirmed=__woaReadRuntimeJson(key)||{};
    return confirmed.owner===__woaRuntimeTabId
  }catch(error){
    // Storage can be unavailable in a privacy-restricted browser. The
    // per-tab in-flight guard below still prevents overlapping refreshes.
    return true
  }
}

function __woaPublishStateChange(version){
  if(!version)return;
  try{localStorage.setItem(__woaStateBroadcastKey,JSON.stringify({owner:__woaRuntimeTabId,version:String(version),at:Date.now()}))}catch(error){}
}

window.addEventListener('storage',function(event){
  if(isPublic||!event||event.key!==__woaStateBroadcastKey||!event.newValue)return;
  var message;
  try{message=JSON.parse(event.newValue)}catch(error){return}
  if(!message||message.owner===__woaRuntimeTabId||!message.version||String(message.version)===String(__woaLastDataVersion||''))return;
  // Hidden tabs wait for their normal focus refresh. The visible tab updates
  // immediately, so another open WheelsonAuto tab never leaves stale data on screen.
  if(document.hidden)return;
  refreshData(true)
});

var __woaSessionExpiredKey='woa-session-expired';
var __woaSessionLocking=false;
function __woaSessionRequestPath(input){
  if(typeof input==='string')return input;
  return input&&typeof input.url==='string'?input.url:''
}
function __woaLockExpiredSession(broadcast){
  if(isPublic||__woaSessionLocking)return false;
  __woaSessionLocking=true;
  try{localStorage.removeItem('woa-platform-backup')}catch(error){}
  try{localStorage.removeItem(__woaStateBroadcastKey)}catch(error){}
  if(broadcast!==false){
    try{localStorage.setItem(__woaSessionExpiredKey,JSON.stringify({at:Date.now(),owner:__woaRuntimeTabId}))}catch(error){}
  }
  db=normalize({});
  lastDataFingerprint='';
  __woaLastDataVersion='';
  window.__SERVER_DATA__={};
  var root=document.getElementById('root');
  if(root)root.innerHTML='<main class="session-expired-lock"><section><strong>Session expired</strong><span>Sign in again to continue securely.</span></section></main>';
  var modal=document.getElementById('modal');
  if(modal)modal.innerHTML='';
  var loginPath='/login?expired=1';
  if(window.location&&typeof window.location.replace==='function')window.location.replace(loginPath);
  else if(window.location)window.location.href=loginPath;
  return true
}
function __woaHandleAuthenticatedResponse(response,input){
  var path=__woaSessionRequestPath(input),origin=window.location&&window.location.origin||'',staffApi=/^\/api\//.test(path)||(origin&&path.indexOf(origin+'/api/')===0);
  if(response&&Number(response.status)===401&&staffApi)__woaLockExpiredSession(true);
  return response
}
var __woaAuthenticatedFetch=fetch;
fetch=async function(input,init){
  return __woaHandleAuthenticatedResponse(await __woaAuthenticatedFetch(input,init),input)
};
window.addEventListener('storage',function(event){
  if(!event||event.key!==__woaSessionExpiredKey||!event.newValue)return;
  __woaLockExpiredSession(false)
});

refreshData=async function(silent){
  if(__woaStateSaveInFlight)return false;
  if(isPublic)return false;
  // A background tab must not make the same five-second request as every
  // other open tab. One short lease keeps the normal five-second freshness
  // while avoiding request storms when the owner keeps several tabs open.
  if(silent&&document.hidden&&!__woaClaimRuntimeLease('state-poll',Math.max(LIVE_REFRESH_MS*3,15000)))return false;
  if(__woaStateRefreshInFlight)return __woaStateRefreshInFlight;
  var refreshTask=(async function(){
  try{
    if(silent){
      var versionResponse=await fetch('/api/state/version',{headers:{'Accept':'application/json'},cache:'no-store'});
      if(versionResponse.ok){
        var versionPayload=await versionResponse.json(),nextVersion=String(versionPayload.version||'');
        if(nextVersion&&nextVersion===__woaLastDataVersion)return true;
        if(nextVersion)__woaLastDataVersion=nextVersion
      }
    }
    var response=await fetch('/api/state',{headers:{'Accept':'application/json'},cache:'no-store'});
    if(!response.ok)return false;
    var fresh=normalize(await response.json()),fingerprint=JSON.stringify(fresh);
    if(fingerprint===lastDataFingerprint){
      if(!silent)notify('Already up to date');
      return true
    }
    db=fresh;
    lastDataFingerprint=fingerprint;
    __woaPublishStateChange(__woaLastDataVersion);
    var active=document.activeElement,editing=active&&/INPUT|TEXTAREA|SELECT/.test(active.tagName);
    if(!silent){render();notify('Dashboard refreshed')}
    else if(!editing)queueRender();
    return true
  }catch(error){
    return false
  }
  })();
  __woaStateRefreshInFlight=refreshTask;
  try{return await refreshTask}finally{if(__woaStateRefreshInFlight===refreshTask)__woaStateRefreshInFlight=null}
};
save=async function(){
  var payload='';
  __woaStateSaveInFlight=true;
  try{
    payload=JSON.stringify(db);
    var response=await fetch('/api/state',{method:'PUT',headers:{'Content-Type':'application/json'},body:payload});
    if(response.ok){
      lastDataFingerprint=payload;
      try{var result=await response.json();if(result.version){__woaLastDataVersion=String(result.version);__woaPublishStateChange(__woaLastDataVersion)}}catch(ignore){}
    }
    return response.ok
  }catch(error){
    localStorage.setItem('woa-platform-backup',payload||JSON.stringify(db));
    return false
  }finally{
    __woaStateSaveInFlight=false
  }
};

var __woaAutoApiSyncBase=autoApiSync;
autoApiSync=async function(force){
  if(isPublic||!isOwner())return false;
  // A successful automatic provider sync is shared state. Hold the lease for
  // the normal sync interval so several owner tabs cannot all hit Clover,
  // Stripe, Telnyx, or other provider adapters at once.
  if(!force&&!__woaClaimRuntimeLease('provider-auto-sync',API_AUTO_SYNC_MS+5000))return false;
  return __woaAutoApiSyncBase(force)
};

// Role home screens should show one primary queue. Full lists live in their
// dedicated tabs, so do not insert a second copy above the same work.
ManagerPortal=__woaManagerPortalRoleQueueBase;
MechanicPortal=__woaMechanicPortalRoleQueueBase;

isInventoryVehicle=function(v){
  var status=String(v&&v.status||'').trim().toLowerCase();
  return !normName(v&&v.currentCustomer)&&/^(ready|available|in\s*lot|inlot|inventory)$/.test(status)
};

function isAssignedFleetVehicle(v){
  var status=String(v&&v.status||'').trim().toLowerCase();
  return status!=='removed'&&(!!normName(v&&v.currentCustomer)||status==='rented')
}

function isFleetReviewVehicle(v){
  var status=String(v&&v.status||'').trim().toLowerCase();
  return status!=='removed'&&!isInventoryVehicle(v)&&!isAssignedFleetVehicle(v)
}

function fleetPrepReviewRecords(){
  var jobs=inLotMaintenanceJobs().filter(isOpenMaintenance),jobVehicleIds={};
  jobs.forEach(function(job){if(job.vehicleId)jobVehicleIds[String(job.vehicleId)]=true});
  return{
    jobs:jobs,
    vehicles:(db.vehicles||[]).filter(function(v){return isFleetReviewVehicle(v)&&!jobVehicleIds[String(v.id||'')]})
  }
}

