  if(action==='native-save-site-settings'){var site=await post('/api/public-site/settings',{defaultWeeklyPayment:Number(val('nativeDefaultWeekly')||0),defaultDownPayment:Number(val('nativeDefaultDown')||0),pickupSlotMinutes:Number(val('nativePickupMinutes')||60),pickupCapacity:Number(val('nativePickupCapacity')||2)});if(!site.ok){notify(site.error||'Website defaults did not save');return}await refreshData(true);closeModal();WebsiteNative();notify('Website defaults saved');return}
  if(action==='native-create-onboarding'){b.disabled=true;var created=await post('/api/onboarding/links',{applicationId:id});b.disabled=false;if(!created.ok){notify(created.error||'Onboarding link could not be created');return}await refreshData(true);openNativeApplication(id,created.onboarding&&created.onboarding.url);notify('Application approved and secure link created');return}
