  if(action==='native-copy-onboarding'){var app=(db.applications||[]).find(function(a){return a.id===id}),link=app&&nativeOnboardingLinkForApplication(app);if(!link){notify('Create or regenerate the secure link first');return}navigator.clipboard.writeText(link);notify('Secure onboarding link copied');return}
  if(action==='native-copy-visible-link'){var visible=val('nativeOnboardingLink');if(visible)navigator.clipboard.writeText(visible);notify('Secure onboarding link copied');return}
